import React, { useEffect, useState, useCallback } from 'react';
import api from '../../utils/api';
import toast from 'react-hot-toast';

const fmt = (n) => `₹${parseFloat(n||0).toLocaleString('en-IN')}`;
  // const emptyForm = { name:'', description:'', short_desc:'', category_id:'', brand_id:'', price:'', compare_price:'', cost_price:'', stock:'', sku:'', tags:'', is_featured:false, is_new_arrival:false, is_active:true };

export default function AdminProducts() {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [brands, setBrands]     = useState([]);
  const [total, setTotal]       = useState(0);
  const [loading, setLoading]   = useState(true);
  const [page, setPage]         = useState(1);
  const [search, setSearch]     = useState('');
  const [catFilter, setCatFilter] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving]     = useState(false);
  const [editId, setEditId]     = useState(null);
  const [imageUrl, setImageUrl] = useState('');

  const [form, setForm]= useState(emptyForm);

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const q = new URLSearchParams({ page, limit:15 });
      if (search) q.set('search', search);
      if (catFilter) q.set('category', catFilter);
      const r = await api.get(`/products?${q}`);
      setProducts(r.data.products);
      setTotal(r.data.total);
    } catch {} finally { setLoading(false); }
  }, [page, search, catFilter]);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);
  useEffect(() => {
    api.get('/categories').then(r => setCategories(r.data.categories)).catch(()=>{});
    api.get('/brands').then(r => setBrands(r.data.brands)).catch(()=>{});
  }, []);

  const handleSave = async (e) => {
    e.preventDefault();
    if (!form.name || !form.price) { toast.error('Name and price are required.'); return; }
    setSaving(true);
    try {
      const payload = {
  ...form,
  tags: form.tags ? form.tags.split(',').map(t=>t.trim()) : [],
  images: imageUrl ? [
    {
      url: imageUrl,
      alt: form.name,
      is_primary: true
    }
  ] : []
};console.log("IMAGE URL:", imageUrl);
      if (editId) { await api.put(`/products/${editId}`, payload); toast.success('Product updated!'); }
      else        { await api.post('/products', payload); toast.success('Product created!'); }
      setShowForm(false); setForm(emptyForm); setEditId(null);
      fetchProducts();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to save.'); }
    finally { setSaving(false); }

  };

  const handleEdit = (p) => {
    setForm({ ...p, tags: Array.isArray(p.tags) ? p.tags.join(', ') : '', category_id: p.category_id || '', brand_id: p.brand_id || '' });
    setEditId(p.id); setShowForm(true);
    window.scrollTo({ top: 0 });
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Deactivate this product?')) return;
    try { await api.delete(`/products/${id}`); toast.success('Product deactivated.'); fetchProducts(); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed.'); }
  };
  const handleImageUpload = async (e) => {
  const file = e.target.files[0];
  if (!file) return;

  const formData = new FormData();
  formData.append("image", file);

  try {
    console.log("Uploading file...");

    const res = await fetch("http://localhost:5000/api/upload", {
      method: "POST",
      body: formData
    });

    const data = await res.json();

    console.log("UPLOAD RESPONSE:", data);

    if (data.url) {
      setImageUrl(data.url);
      toast.success("Image uploaded successfully ✅");
    } else {
      toast.error("Upload failed ❌");
    }

  } catch (err) {
    console.log(err);
    toast.error("Upload error ❌");
  }
  // setImageUrl('');
};
  const F = ({ label, children }) => (
    <div><label className="form-label">{label}</label>{children}</div>
  );

  return (
    <div className="space-y-5">
      {/* Product form */}
      {showForm && (
        <div className="bg-white border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-5">
            <h2 className="font-serif text-xl">{editId ? 'Edit Product' : 'Add New Product'}</h2>
            <button onClick={() => { setShowForm(false); setForm(emptyForm); setEditId(null); }} className="text-gray-400 hover:text-luxury-black text-xl">✕</button>
          </div>
          <form onSubmit={handleSave}>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4">
              <div className="lg:col-span-2"><F label="Product Name *"><input type="text" className="form-input" value={form.name} onChange={e=>setForm({...form,name:e.target.value})} /></F></div>
             <F label="SKU">
  <input
    type="text"
    className="form-input"
    value={form.sku || ''}
    onChange={(e) =>
      setForm(prev => ({ ...prev, sku: e.target.value }))
    }
  />
</F>

<F label="Price (₹) *">
  <input
    type="number"
    className="form-input"
    step="0.01"
    value={form.price}
    onChange={(e) =>
      setForm(prev => ({ ...prev, price: e.target.value }))
    }
  />
</F>

<F label="Compare Price (₹)">
  <input
    type="number"
    className="form-input"
    step="0.01"
    value={form.compare_price || ''}
    onChange={(e) =>
      setForm(prev => ({ ...prev, compare_price: e.target.value }))
    }
  />
</F>

<F label="Cost Price (₹)">
  <input
    type="number"
    className="form-input"
    step="0.01"
    value={form.cost_price || ''}
    onChange={(e) =>
      setForm(prev => ({ ...prev, cost_price: e.target.value }))
    }
  />
</F>

<F label="Stock">
  <input
    type="number"
    className="form-input"
    value={form.stock || 0}
    onChange={(e) =>
      setForm(prev => ({ ...prev, stock: e.target.value }))
    }
  />
</F>

<F label="Category">
  <select
    className="form-select"
    value={form.category_id || ''}
    onChange={(e) =>
      setForm(prev => ({ ...prev, category_id: e.target.value }))
    }
  >
    <option value="">Select category</option>
    {categories.map(c => (
      <option key={c.id} value={c.id}>{c.name}</option>
    ))}
  </select>
</F>

<F label="Brand">
  <select
    className="form-select"
    value={form.brand_id || ''}
    onChange={(e) =>
      setForm(prev => ({ ...prev, brand_id: e.target.value }))
    }
  >
    <option value="">Select brand</option>
    {brands.map(b => (
      <option key={b.id} value={b.id}>{b.name}</option>
    ))}
  </select>
</F>
              <div className="md:col-span-2"><F label="Short Description"><input type="text" className="form-input" value={form.short_desc||''} onChange={e=>setForm({...form,short_desc:e.target.value})} /></F></div>
              <div className="md:col-span-2 lg:col-span-3"><F label="Full Description"><textarea rows={3} className="form-input resize-none" value={form.description||''} onChange={e=>setForm({...form,description:e.target.value})} /></F></div>
              <div className="md:col-span-2"><F label="Tags (comma-separated)"><input type="text" className="form-input" placeholder="dress, silk, women, new" value={form.tags||''} onChange={e=>setForm({...form,tags:e.target.value})} /></F></div>
            </div>
            <F label="Product Image">
  <input type="file" className="form-input" onChange={handleImageUpload} />
  {imageUrl && (
    <img src={imageUrl} alt="preview" className="mt-2 w-20 h-20 object-cover border" />
  )}
</F>
            <div className="flex items-center gap-6 mb-5">
              {[['is_featured','Featured'],['is_new_arrival','New Arrival'],['is_active','Active']].map(([k,l])=>(
                <label key={k} className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" checked={!!form[k]} onChange={e=>setForm({...form,[k]:e.target.checked})} className="w-4 h-4 accent-gold" />
                  <span className="text-sm text-gray-700">{l}</span>
                </label>
              ))}
            </div>
            <div className="flex gap-3">
              <button type="submit" disabled={saving || !imageUrl} className="btn btn-primary">
                {saving ? <><div className="spinner spinner-sm spinner-white" /> Saving...</> : editId ? 'Update Product' : 'Create Product'}
              </button>
              <button type="button" onClick={() => { setShowForm(false); setForm(emptyForm); setEditId(null); }} className="btn btn-ghost">Cancel</button>
            </div>
          </form>
        </div>
      )}

      {/* Table */}
      <div className="bg-white border border-gray-200">
        {/* Header */}
        <div className="flex flex-wrap items-center gap-3 p-4 border-b border-gray-100">
          <div className="relative flex-1 min-w-48">
            <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
            <input className="form-input pl-9 py-2 text-sm" placeholder="Search products..."
              value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} />
          </div>
          <select className="form-select py-2 text-sm w-auto" value={catFilter} onChange={e=>{ setCatFilter(e.target.value); setPage(1); }}>
            <option value="">All Categories</option>
            {categories.map(c=><option key={c.id} value={c.slug}>{c.name}</option>)}
          </select>
          {!showForm && (
            <button onClick={() => setShowForm(true)} className="btn btn-primary btn-sm">+ Add Product</button>
          )}
        </div>

        <table className="data-table">
          <thead>
            <tr><th>Product</th><th>SKU</th><th>Category</th><th>Price</th><th>Stock</th><th>Status</th><th>Rating</th><th>Actions</th></tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={8} className="text-center py-12"><div className="spinner spinner-gold mx-auto" /></td></tr>
            ) : products.length === 0 ? (
              <tr><td colSpan={8} className="text-center py-12 text-gray-400 text-sm">No products found</td></tr>
            ) : products.map(p => (
              <tr key={p.id}>
                <td>
                  <p className="text-sm font-medium max-w-[180px] truncate">{p.name}</p>
                  <p className="text-xs text-gray-400">{p.brand_name}</p>
                </td>
                <td className="text-xs font-mono text-gray-400">{p.sku || '—'}</td>
                <td className="text-xs text-gray-500">{p.category_name || '—'}</td>
                <td>
                  <p className="text-sm font-medium">{fmt(p.price)}</p>
                  {p.compare_price && <p className="text-xs text-gray-400 line-through">{fmt(p.compare_price)}</p>}
                </td>
                <td>
                  <span className={`text-xs font-medium ${p.stock === 0 ? 'text-red-500' : p.stock <= 5 ? 'text-amber-600' : 'text-green-600'}`}>
                    {p.stock === 0 ? 'Out of Stock' : p.stock}
                  </span>
                </td>
                <td>
                  <div className="flex flex-col gap-1">
                    {p.is_active ? <span className="badge badge-success text-[9px]">Active</span> : <span className="badge bg-gray-100 text-gray-400 text-[9px]">Inactive</span>}
                    {p.is_featured && <span className="badge bg-amber-50 text-amber-600 text-[9px]">Featured</span>}
                    {p.is_new_arrival && <span className="badge badge-new text-[9px]">New</span>}
                  </div>
                </td>
                <td className="text-sm">{parseFloat(p.avg_rating||0).toFixed(1)} ★ <span className="text-xs text-gray-400">({p.review_count||0})</span></td>
                <td>
                  <div className="flex gap-2">
                    <button onClick={() => handleEdit(p)} className="text-xs text-blue-500 hover:text-blue-700 underline">Edit</button>
                    <button onClick={() => handleDelete(p.id)} className="text-xs text-red-400 hover:text-red-600 underline">Remove</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        <div className="flex items-center justify-between px-4 py-3 border-t border-gray-100">
          <p className="text-xs text-gray-400">{total} total products</p>
          <div className="flex gap-1">
            <button disabled={page<=1} onClick={()=>setPage(p=>p-1)} className="w-8 h-8 border border-gray-200 text-sm flex items-center justify-center hover:border-luxury-black disabled:opacity-30">←</button>
            <span className="w-8 h-8 flex items-center justify-center text-xs">{page}</span>
            <button disabled={products.length<15} onClick={()=>setPage(p=>p+1)} className="w-8 h-8 border border-gray-200 text-sm flex items-center justify-center hover:border-luxury-black disabled:opacity-30">→</button>
          </div>
        </div>
      </div>
    </div>
  );
}
